mapper.select:
SELECT p.id, p.payment_no, p.sales_order_id, p.org_id, p.total_receivable, p.received_amount, (COALESCE(p.total_receivable, 0) - COALESCE(p.received_amount, 0)) AS unreceived_amount, p.status, p.is_locked, p.create_time, p.update_time, s.order_no, o.org_name, CASE p.status WHEN 0 THEN '未收款' WHEN 1 THEN '部分收款' WHEN 2 THEN '已收款' WHEN 3 THEN '已锁定' ELSE '未知' END AS status_name FROM t_sales_payment p INNER JOIN t_sales_order s ON p.sales_order_id = s.id INNER JOIN t_downstream_org o ON p.org_id = o.id WHERE 1=1
AND p.org_id = #{orgId}
AND p.status = #{status}
ORDER BY p.create_time DESC
